function CartLine({ price, qty }) {
  const [coupon, setCoupon] = useState(false);
  const subtotal = price * qty;
  const total = coupon ? subtotal * 0.9 : subtotal;
  return (
    <>
      <p>Total: {total}</p>
      <input type="checkbox" checked={coupon}
        onChange={(e) => setCoupon(e.target.checked)} />
    </>
  );
}
